
apt-get update && apt-get install -y nodejs npm git
rm -rf /opt/my-website
git clone https://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@github.com/minhtaneditor-hue/7daychallenge.git /opt/my-website
echo "" | base64 -d > /opt/my-website/.env
echo "" | base64 -d > /opt/my-website/brain.db
cd /opt/my-website && npm install
cat << EOF > /etc/systemd/system/mywebsite.service
[Unit]
Description=My Website
After=network.target

[Service]
EnvironmentFile=/opt/my-website/.env
Type=simple
User=root
WorkingDirectory=/opt/my-website
ExecStart=/usr/bin/node server.js
Restart=on-failure

[Install]
WantedBy=multi-user.target
EOF
systemctl daemon-reload
systemctl enable mywebsite
systemctl restart mywebsite
systemctl status mywebsite --no-pager

